static int compute_launch_blocks(int n)
{
	int device = 0;
	cudaDeviceProp prop;
	gpuErrchk(cudaGetDevice(&device));
	gpuErrchk(cudaGetDeviceProperties(&prop, device));
	int blocks = (n + 255) / 256;
	int cap = prop.multiProcessorCount * 32;
	if( blocks > cap ) blocks = cap;
	if( blocks < 1 ) blocks = 1;
	return blocks;
}

unsigned long long run_event_based_simulation_baseline(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0 )
		printf("Beginning event based simulation...\n");

	gpuErrchk(cudaMemset(GSD.verification, 0, sizeof(unsigned long)));

	int threads = 256;
	int blocks = compute_launch_blocks(in.lookups);
	xs_lookup_kernel_baseline<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	unsigned long long verification = 0;
	gpuErrchk(cudaMemcpy(&verification, GSD.verification, sizeof(unsigned long long), cudaMemcpyDeviceToHost));
	return verification;
}

unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData GSD, int mype)
{
	char * optimization_name = (char *)"Optimization 1 - Kernel splitting + full material & energy sort";

	if( mype == 0 )
		printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if( mype == 0 )
		printf("Allocating additional data required by optimized kernel...\n");

	size_t sz;
	size_t total_sz = 0;

	sz = (size_t)in.lookups * sizeof(double);
	gpuErrchk(cudaMalloc((void **)&GSD.p_energy_samples, sz));
	total_sz += sz;
	GSD.length_p_energy_samples = in.lookups;

	sz = (size_t)in.lookups * sizeof(int);
	gpuErrchk(cudaMalloc((void **)&GSD.mat_samples, sz));
	total_sz += sz;
	GSD.length_mat_samples = in.lookups;

	if( mype == 0 )
		printf("Allocated an additional %.0lf MB of data on GPU.\n", total_sz/1024.0/1024.0);

	int threads = 256;
	int blocks = compute_launch_blocks(in.lookups);

	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	if( mype == 0 )
		printf("finished sampling...\n");

	double start = get_time();

	thrust::device_ptr<int> mat_begin(GSD.mat_samples);
	thrust::device_ptr<int> mat_end(GSD.mat_samples + in.lookups);
	thrust::device_ptr<double> energy_begin(GSD.p_energy_samples);
	thrust::sort_by_key(mat_begin, mat_end, energy_begin);
	gpuErrchk(cudaDeviceSynchronize());

	double stop = get_time();
	if( mype == 0 )
		printf("Material sort took %.3lf seconds\n", stop-start);

	start = get_time();

	std::vector<int> h_mat_samples(in.lookups);
	gpuErrchk(cudaMemcpy(h_mat_samples.data(), GSD.mat_samples, (size_t)in.lookups * sizeof(int), cudaMemcpyDeviceToHost));

	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[h_mat_samples[l]]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	stop = get_time();
	if( mype == 0 )
		printf("Counting samples and offsets took %.3lf seconds\n", stop-start);

	start = stop;

	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] > 1 )
		{
			thrust::device_ptr<double> e_begin(GSD.p_energy_samples + offsets[m]);
			thrust::device_ptr<double> e_end(GSD.p_energy_samples + offsets[m] + num_samples_per_mat[m]);
			thrust::device_ptr<int> m_begin(GSD.mat_samples + offsets[m]);
			thrust::sort_by_key(e_begin, e_end, m_begin);
		}
	}
	gpuErrchk(cudaDeviceSynchronize());

	stop = get_time();
	if( mype == 0 )
		printf("Energy Sorts took %.3lf seconds\n", stop-start);

	start = get_time();

	gpuErrchk(cudaMemset(GSD.verification, 0, sizeof(unsigned long)));
	xs_lookup_kernel_optimization_1<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	unsigned long long verification = 0;
	gpuErrchk(cudaMemcpy(&verification, GSD.verification, sizeof(unsigned long long), cudaMemcpyDeviceToHost));

	stop = get_time();
	if( mype == 0 )
		printf("XS Lookups took %.3lf seconds\n", stop-start);

	gpuErrchk(cudaFree(GSD.p_energy_samples));
	gpuErrchk(cudaFree(GSD.mat_samples));

	return verification;
}

